const OBJECT_PROPERTIES = Dict{Tuple{ANARIDataType, String}, Vector{PropertySpec}}(
    (ANARI_INSTANCE, "") => [PropertySpec("bounds", ANARI_FLOAT32_BOX3, Symbol[])],
    (ANARI_DEVICE, "") => [PropertySpec("version", ANARI_INT32, [:required]), PropertySpec("version.major", ANARI_INT32, Symbol[]), PropertySpec("version.minor", ANARI_INT32, Symbol[]), PropertySpec("version.patch", ANARI_INT32, Symbol[]), PropertySpec("version.name", ANARI_STRING, Symbol[]), PropertySpec("geometryMaxIndex", ANARI_UINT64, [:required])],
    (ANARI_FRAME, "") => [PropertySpec("duration", ANARI_FLOAT32, [:required]), PropertySpec("renderProgress", ANARI_FLOAT32, Symbol[]), PropertySpec("refinementProgress", ANARI_FLOAT32, Symbol[])],
    (ANARI_GROUP, "") => [PropertySpec("bounds", ANARI_FLOAT32_BOX3, Symbol[])],
    (ANARI_WORLD, "") => [PropertySpec("bounds", ANARI_FLOAT32_BOX3, Symbol[])],
    (ANARI_INSTANCE, "motionScaleRotationTranslation") => [PropertySpec("bounds", ANARI_FLOAT32_BOX3, Symbol[])],
    (ANARI_INSTANCE, "motionTransform") => [PropertySpec("bounds", ANARI_FLOAT32_BOX3, Symbol[])],
)

const ATTRIBUTES = Dict{String, ANARIDataType}(
    "color" => ANARI_FLOAT32_VEC4,
    "worldPosition" => ANARI_FLOAT32_VEC4,
    "worldNormal" => ANARI_FLOAT32_VEC4,
    "objectPosition" => ANARI_FLOAT32_VEC4,
    "objectNormal" => ANARI_FLOAT32_VEC4,
    "attribute0" => ANARI_FLOAT32_VEC4,
    "attribute1" => ANARI_FLOAT32_VEC4,
    "attribute2" => ANARI_FLOAT32_VEC4,
    "attribute3" => ANARI_FLOAT32_VEC4,
    "primitiveId" => ANARI_UINT64,
)

object_subtypes(object_type::ANARIDataType) = get(OBJECT_SUBTYPES, object_type, String[])

function parameter_specs(object_type::ANARIDataType, subtype::AbstractString = "")
    return get(OBJECT_PARAMETERS, (object_type, String(subtype)), ParameterSpec[])
end

function property_specs(object_type::ANARIDataType, subtype::AbstractString = "")
    return get(OBJECT_PROPERTIES, (object_type, String(subtype)), PropertySpec[])
end

function parameter_spec(
    object_type::ANARIDataType,
    subtype::AbstractString,
    name::AbstractString,
)
    for spec in parameter_specs(object_type, subtype)
        spec.name == name && return spec
    end
    return nothing
end

is_required(spec::ParameterSpec) = :required in spec.tags
